      .s_axis_aresetn(spi_resetn),
      .s_axis_ready(sync_ready),
      .s_axis_valid(sync_valid),
      .s_axis_data(sync_data),
      .s_axis_room(),
      .s_axis_tlast(),
      .s_axis_tkeep(),
      .s_axis_full(),
      .s_axis_almost_full(),

      .m_axis_aclk(clk),
      .m_axis_aresetn(up_sw_resetn),
