          if (latch_sdi)
            sdi_data_latch[i*DATA_WIDTH+:DATA_WIDTH] <= {data_sdi_shift, sdi[i]};
        end
      end

      always @(negedge echo_sclk or posedge cs_activate) begin
        if (cs_activate) begin
          sdi_counter     <= 8'b0;
          last_sdi_bit_r  <= 1'b0;
          latch_sdi       <= 1'b0;
        end else begin
