  parameter ASYNC_TRIG = 0,
  parameter CMD_MEM_ADDRESS_WIDTH = 4,
  parameter SDO_MEM_ADDRESS_WIDTH = 4,
  parameter DATA_WIDTH = 8, // Valid data widths values are 8/16/24/32
  parameter NUM_OF_SDIO = 1,
  parameter SDO_STREAMING = 0
