  wire ctrl_is_enabled;
  reg spi_enabled = 1'b0;

  assign interconnect_dir = spi_enabled;

  always @(posedge ctrl_clk) begin
    if (ctrl_enable) begin
      ctrl_do_enable <= 1'b1;
    end else if (ctrl_is_enabled) begin
      ctrl_do_enable <= 1'b0;
    end
  end

  assign ctrl_enabled = ctrl_is_enabled | ctrl_do_enable;

  always @(posedge spi_clk) begin
    spi_enabled <= spi_enable | spi_active;
  end

  sync_bits #(
    .NUM_OF_BITS(1),
    .ASYNC_CLK(1)
  ) i_sync_enable (
    .in_bits(ctrl_do_enable),
    .out_clk(spi_clk),
    .out_resetn(1'b1),
    .out_bits(spi_enable));

  sync_bits #(
    .NUM_OF_BITS(1),
    .ASYNC_CLK(1)
  ) i_sync_enabled (
    .in_bits(spi_enabled),
    .out_clk(ctrl_clk),
    .out_resetn(1'b1),
    .out_bits(ctrl_is_enabled));

  end else begin
    assign spi_enable = ctrl_enable;
    assign ctrl_enabled = spi_enable | spi_active;
    assign interconnect_dir = ctrl_enabled;
  end endgenerate

  assign spi_cmd_rd_addr_next = spi_cmd_rd_addr + 1;

  wire trigger_s;
  sync_bits #(
    .NUM_OF_BITS(1),
    .ASYNC_CLK(ASYNC_TRIG)
  ) i_sync_trigger (
    .in_bits(trigger),
    .out_clk(spi_clk),
    .out_resetn(1'b1),
    .out_bits(trigger_s));

  always @(posedge spi_clk) begin
    if (!spi_resetn) begin
      trigger_last_reg <= 1'b0;
    end else begin
      trigger_last_reg <= trigger_s;
    end
  end

  assign trigger_posedge = trigger_s && !trigger_last_reg;

  reg  last_cmd;
  wire last_cmd_accept;
  wire offload_disable_pending;

  // Detects when offload disable is requested but operations are still in progress.
  // spi_enable goes low when the user disables offload, but interconnect_dir
  // remains high while the offload completes its current operations.
  assign offload_disable_pending = !spi_enable && interconnect_dir;

  always @(posedge spi_clk) begin
    if (!spi_resetn) begin
      spi_active <= 1'b0;
    end else begin
      if (!spi_active) begin
        // start offload when we have a valid trigger and offload is enabled
        if (trigger_posedge && spi_enable)
          spi_active <= 1'b1;
      // Deassert spi_active when offload execution is complete.
      // Conditions for completion:
      // - (last_cmd_accept || !offload_cmd_valid): Either processed the last command OR no offload commands remain
      // - !(offload_disable_pending && sdi_data_valid): Prevent mode switch if SDI data is pending during disable
      // The !offload_cmd_valid condition handles edge cases where sdi_data_valid remains continuously asserted
      end else if ((last_cmd_accept || !offload_cmd_valid) && !(offload_disable_pending && sdi_data_valid)) begin
        spi_active <= 1'b0;
      end
    end
  end

  // Manages the offload_cmd_valid flag to track offload command availability.
  // This signal must be coordinated with spi_active to ensure proper offload sequencing.
  // offload_cmd_valid is high during the entire offload execution cycle.
  always @(posedge spi_clk) begin
    if (!spi_resetn) begin
      offload_cmd_valid <= 1'b0;
    end else begin
      if (!offload_cmd_valid) begin
        // Assert offload_cmd_valid when starting a new offload cycle.
        // Requires: valid trigger, offload enabled, and spi_active is low (previous cycle complete)
        if (trigger_posedge && spi_enable && !spi_active) begin
          offload_cmd_valid <= 1'b1;
        end

      // Deassert offload_cmd_valid when the last command in the buffer is processed
      end else if (last_cmd_accept) begin
        offload_cmd_valid <= 1'b0;
      end
    end
  end

  always @(posedge spi_clk) begin
    if (!cmd_valid) begin
      spi_cmd_rd_addr <= 'h00;
    end else if (cmd_ready) begin
      spi_cmd_rd_addr <= spi_cmd_rd_addr_next;
      last_cmd <= spi_cmd_rd_addr + 2'h2 == ctrl_cmd_wr_addr;
    end
  end

  // Detects when the offload engine is processing the last command in the buffer.
  // This occurs when reading a command (cmd_ready) and the next read address
  // equals the write address (caught up to all written commands).
  assign last_cmd_accept = cmd_ready && last_cmd;

  always @(posedge spi_clk) begin
    if (!sdo_mem_valid) begin
      spi_sdo_rd_addr <= 'h00;
    end else if (sdo_data_ready && (sdo_source_select == SDO_SOURCE_MEM)) begin
      spi_sdo_rd_addr <= spi_sdo_rd_addr + 1'b1;
    end
  end

  always @(posedge spi_clk) begin
    if (!spi_resetn) begin
      sdo_mem_valid <= 1'b0;
    end else begin
      if (!spi_active && trigger_posedge && spi_enable) begin
        sdo_mem_valid <= (ctrl_sdo_wr_addr != 'h00); // if ctrl_sdo_wr_addr is 0, mem is empty
      end else if (sdo_data_ready && sdo_mem_valid && (spi_sdo_rd_addr + 1'b1 == ctrl_sdo_wr_addr))  begin
        sdo_mem_valid <= 1'b0;
      end
    end
  end

  always @(posedge ctrl_clk) begin
    if (ctrl_mem_reset)
      ctrl_cmd_wr_addr <= 'h00;
    else if (ctrl_cmd_wr_en)
      ctrl_cmd_wr_addr <= ctrl_cmd_wr_addr + 1'b1;
  end

  always @(posedge ctrl_clk) begin
    if (ctrl_cmd_wr_en)
      cmd_mem[ctrl_cmd_wr_addr] <= ctrl_cmd_wr_data;
  end

  always @(posedge ctrl_clk) begin
    if (ctrl_mem_reset)
      ctrl_sdo_wr_addr <= 'h00;
    else if (ctrl_sdo_wr_en)
      ctrl_sdo_wr_addr <= ctrl_sdo_wr_addr + 1'b1;
  end

  always @(posedge ctrl_clk) begin
    if (ctrl_sdo_wr_en)
