`timescale 1ns/100ps

module system_top #(
  parameter ALERT_SPI_N = 0,
  parameter NUM_OF_SDI = 4
) (
  input           clk_125,
  input           resetn,

  input           sw_4,
  input           sw_5,
  input   [7:0]   dip_sw_1_to_8,
  output  [23:0]  leds_0_to_23,

  input           uart_rx,
  output          uart_tx,

  input           spi_miso,
  output          spi_sclk,
  output          spi_ssn,
  output          spi_mosi,

  input   [3:0]   sdi_bus,
  output          cs,
  output          sdo,
  output          sclk,

  inout           iic_scl,
  inout           iic_sda
);

  wire    [31:0]  gpio0_o;
  wire    [31:0]  gpio0_i;
  wire    [31:0]  gpio0_en_o;

  wire    [31:0]  gpio1_o;
  wire    [31:0]  gpio1_i;
  wire    [31:0]  gpio1_en_o;

  wire    [NUM_OF_SDI-1:0]   sdi_bus_i;

  assign leds_0_to_23 = gpio0_o[23:0];
  assign gpio0_i[31:24] = dip_sw_1_to_8;
  assign gpio1_i[31:30] = {sw_5, sw_4};
  assign gpio1_i[27:0] = gpio1_o[27:0];

  assign gpio1_i[28] = ALERT_SPI_N ? sdi_bus[1] : 0;
  assign gpio1_i[29] = ALERT_SPI_N ? sdi_bus[3] : 0;

  assign sdi_bus_i = (ALERT_SPI_N == 0) ? sdi_bus[NUM_OF_SDI-1:0] : sdi_bus[0];

  ad738x_fmc_lfcpnx ad738x_fmc_lfcpnx_inst (
    .gpio0_o(gpio0_o),
    .gpio0_i(gpio0_i),
    .gpio0_en_o(gpio0_en_o),
    .gpio1_o(gpio1_o),
    .gpio1_i(gpio1_i),
    .gpio1_en_o(gpio1_en_o),
    .scl_io (iic_scl),
    .sda_io (iic_sda),
    .rstn_i (resetn),
    .ssn_o (spi_ssn),
    .mosi_o (spi_mosi),
    .sclk_o (spi_sclk),
    .miso_i (spi_miso),
    .rxd_i (uart_rx),
    .txd_o (uart_tx),
    .clk_125 (clk_125),
    .spi_master0_cs(cs),
    .spi_master0_sclk(sclk),
    .spi_master0_sdi(sdi_bus_i),
    .spi_master0_sdo(sdo),
    .spi_master0_sdo_t(),
    .spi_master0_three_wire());

endmodule

